import {motion} from "framer-motion";


const transition = (OgComponent) => {


    return (
        <>
            <OgComponent />

                <motion.div
                    className="slide-in"
                    initial={{ scaleY: 0 }}
                    animate={{ scaleY: 0 }}
                    exit={{ scaleY: 1 }}
                    transition={{ duration: 1, ease: [.22, 1, .36, 1] }}
                />
                <motion.div
                    className="slide-out"
                    initial={{ scaleY: 1 }}
                    animate={{ scaleY: 0 }}
                    exit={{ scaleY: 1 }}
                    transition={{ duration: 1, ease: [.22, 1, .36, 1] }}
                />



        </>

    )
}
export default Transition
